import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// --- HELPER FUNCTIONS ---
const isSameDay = (d1, d2) => d1.toDateString() === d2.toDateString();
const isSameMonth = (d1, d2) => d1.getMonth() === d2.getMonth() && d1.getFullYear() === d2.getFullYear();
const isSameWeek = (d1, d2) => {
    const start = new Date(d2);
    start.setHours(0,0,0,0);
    start.setDate(start.getDate() - start.getDay() + 1); 
    const end = new Date(start);
    end.setDate(end.getDate() + 6);
    return d1 >= start && d1 <= end;
};

// --- ICONS ---
const Icons = {
    Task: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12h3.75M9 15h3.75M9 18h3.75m3 .75H18a2.25 2.25 0 002.25-2.25V6.108c0-1.135-.845-2.098-1.976-2.192a48.424 48.424 0 00-1.123-.08m-5.801 0c-.065.21-.1.433-.1.664 0 .414.336.75.75.75h4.5a.75.75 0 00.75-.75 2.25 2.25 0 00-.1-.664m-5.8 0A2.251 2.251 0 0113.5 2.25H15c1.012 0 1.867.668 2.15 1.586m-5.8 0c-.376.023-.75.05-1.124.08C9.095 4.01 8.25 4.973 8.25 6.108V8.25m0 0H4.875c-.621 0-1.125.504-1.125 1.125v11.25c0 .621.504 1.125 1.125 1.125h9.75c.621 0 1.125-.504 1.125-1.125V9.375c0-.621-.504-1.125-1.125-1.125H8.25zM6.75 12h.008v.008H6.75V12zm0 3h.008v.008H6.75V15zm0 3h.008v.008H6.75V18z" /></svg>),
    Schedule: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M6.75 3v2.25M17.25 3v2.25M3 18.75V7.5a2.25 2.25 0 012.25-2.25h13.5A2.25 2.25 0 0121 7.5v11.25m-18 0A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75m-18 0v-7.5A2.25 2.25 0 015.25 9h13.5A2.25 2.25 0 0121 11.25v7.5" /></svg>),
    ArrowRight: () => (<svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg>),
    Back: () => (<svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" /></svg>),
    Edit: () => (<svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M16.862 4.487l1.687-1.688a1.875 1.875 0 112.652 2.652L10.582 16.07a4.5 4.5 0 01-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 011.13-1.897l8.932-8.931zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0115.75 21H5.25A2.25 2.25 0 013 18.75V8.25A2.25 2.25 0 015.25 6H10" /></svg>)
};

const TaskManager = () => {
  const { user } = useAuth();
  // Đảm bảo updateTask được lấy ra từ DataContext
  const { tasks, addTask, deleteTask, updateTask, staffList, disciplineTypes, schedules, addSchedule, deleteSchedule, updateSchedule } = useData();
  
  const activeDisciplines = disciplineTypes.filter(d => d.status === 'Active');
  
  const isScheduler = user?.role === 'scheduler';
  const isApprover = ['chief', 'reg', 'op'].includes(user?.role);

  // --- VIEW STATE ---
  const [activeView, setActiveView] = useState('overview'); // 'overview', 'create_task', 'create_schedule', 'manage_tasks', 'manage_schedules'

  // --- FORMS STATE ---
  const [taskPlusForm, setTaskPlusForm] = useState({ 
      title: '', assigneeId: '', description: '',
      startTime: '', endTime: '', assignedRole: 'ST',
      paymentAmount: '', disciplineId: '' // Dùng mức tiền thay vì select
  });

  const [scheduleForm, setScheduleForm] = useState({
      title: '', assigneeId: '', description: '',
      startTime: '', endTime: '', assignedRole: 'ST',
      repeatWeeks: 1, repeatDays: [] 
  });

  const [editingScheduleId, setEditingScheduleId] = useState(null);
  
  // --- INLINE EDIT STATE CHO TASK ---
  const [editingTaskId, setEditingTaskId] = useState(null);
  const [editTaskData, setEditTaskData] = useState({});

  // --- BỘ LỌC TÌM KIẾM ---
  const [filterTaskStaff, setFilterTaskStaff] = useState('all');
  const [filterTaskDay, setFilterTaskDay] = useState('all');
  const [filterTaskTime, setFilterTaskTime] = useState('all'); 
  const [scheduleSearchTerm, setScheduleSearchTerm] = useState('');

  const daysOfWeek = [
      { key: 'Mon', label: 'T2', val: 1 }, { key: 'Tue', label: 'T3', val: 2 }, { key: 'Wed', label: 'T4', val: 3 },
      { key: 'Thu', label: 'T5', val: 4 }, { key: 'Fri', label: 'T6', val: 5 }, { key: 'Sat', label: 'T7', val: 6 },
      { key: 'Sun', label: 'CN', val: 0 }
  ];

  const formatTaskTime = (start, end) => {
      const s = new Date(start);
      const e = new Date(end);
      return (
          <div>
              <div style={{fontWeight:'bold', fontSize:'0.85rem'}}>{s.toLocaleDateString('vi-VN')}</div>
              <div style={{fontSize:'0.8rem', color:'#6b7280'}}>
                  {s.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})} - {e.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
              </div>
          </div>
      );
  };

  // --- LOGIC: CREATE TASK PLUS (Mục 1) ---
  const handleAddTaskPlus = (e) => {
      e.preventDefault();
      if (!taskPlusForm.title || !taskPlusForm.assigneeId || !taskPlusForm.endTime) return alert("Vui lòng điền đủ thông tin!");
      
      const staff = staffList.find(s => s.id === taskPlusForm.assigneeId);
      const disc = activeDisciplines.find(d => d.id === taskPlusForm.disciplineId);
      
      addTask({ 
          ...taskPlusForm, 
          paymentType: taskPlusForm.paymentAmount ? `${Number(taskPlusForm.paymentAmount).toLocaleString()} VNĐ` : '0 VNĐ', // Chuyển đổi thành string hiển thị
          paymentAmount: Number(taskPlusForm.paymentAmount) || 0,
          assigneeName: staff ? staff.name : 'Unknown',
          disciplineName: disc ? disc.name : 'Chưa quy định',
          deadline: taskPlusForm.endTime,
          fromScheduleId: null // Định danh là Task độc lập
      });
      
      alert("Đã giao nhiệm vụ thành công!");
      setTaskPlusForm({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST', paymentAmount: '', disciplineId: '' });
  };

  // --- LOGIC: CREATE SCHEDULE (Mục 2) ---
  const handleAddSchedule = (e) => {
      e.preventDefault();
      if (!scheduleForm.title || !scheduleForm.assigneeId || !scheduleForm.endTime) return alert("Vui lòng điền đủ thông tin!");
      if (scheduleForm.repeatDays.length === 0) return alert("Vui lòng chọn ít nhất một ngày trong tuần!");
      
      const staff = staffList.find(s => s.id === scheduleForm.assigneeId);
      const scheduleData = {
          ...scheduleForm,
          assigneeName: staff ? staff.name : 'Unknown',
          repeatWeeks: Number(scheduleForm.repeatWeeks),
          createdBy: user.username
      };

      if (editingScheduleId && isScheduler) {
          updateSchedule(editingScheduleId, {
              request: { type: 'edit', reason: 'Điều chỉnh thông tin', draftData: scheduleData, requestedBy: user.username, requestedAt: new Date().toISOString() }
          });
          alert("Đã gửi yêu cầu điều chỉnh. Admin sẽ xem xét và phê duyệt.");
      } else {
          // Admin tạo thì duyệt luôn
          if (editingScheduleId) {
              updateSchedule(editingScheduleId, scheduleData);
              deleteRelatedTasks(editingScheduleId); // Xóa task cũ
              generateTasksFromSchedule(scheduleData, editingScheduleId); // Đẻ task mới
              alert("Cập nhật lịch thành công!");
          } else {
              const savedId = addSchedule(scheduleData);
              generateTasksFromSchedule(scheduleData, savedId);
              alert(`Đã lên lịch và tạo tasks cho ${scheduleData.assigneeName}!`);
          }
      }

      setScheduleForm({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST', repeatWeeks: 1, repeatDays: [] });
      setEditingScheduleId(null);
  };

  const generateTasksFromSchedule = (scheduleData, schedId) => {
      const { startTime, endTime, repeatWeeks, repeatDays } = scheduleData;
      const startObj = new Date(startTime);
      const endObj = new Date(endTime);
      const duration = endObj - startObj;
      const targetDayVals = daysOfWeek.filter(d => repeatDays.includes(d.key)).map(d => d.val);

      for (let w = 0; w < repeatWeeks; w++) {
          for (let d = 0; d < 7; d++) {
              const currentCheckDate = new Date(startObj);
              currentCheckDate.setDate(startObj.getDate() + (w * 7) + d);

              if (targetDayVals.includes(currentCheckDate.getDay())) {
                  const taskStart = new Date(currentCheckDate);
                  const taskEnd = new Date(taskStart.getTime() + duration);

                  addTask({
                      title: scheduleData.title,
                      assigneeId: scheduleData.assigneeId,
                      assigneeName: scheduleData.assigneeName,
                      description: scheduleData.description,
                      assignedRole: scheduleData.assignedRole,
                      startTime: taskStart.toISOString(),
                      endTime: taskEnd.toISOString(),
                      paymentType: 'Theo lịch', 
                      deadline: taskEnd.toISOString(),
                      fromScheduleId: schedId,
                      generatedDate: new Date().toISOString()
                  });
              }
          }
      }
  };

  const deleteRelatedTasks = (schedId) => {
      const relatedTasks = tasks.filter(t => t.fromScheduleId === schedId);
      relatedTasks.forEach(t => deleteTask(t.id));
  };

  const handleEditSchedule = (sched) => {
      setActiveView('create_schedule');
      setEditingScheduleId(sched.id);
      setScheduleForm({
          title: sched.title, assigneeId: sched.assigneeId, description: sched.description,
          startTime: sched.startTime, endTime: sched.endTime, assignedRole: sched.assignedRole,
          repeatWeeks: sched.repeatWeeks, repeatDays: sched.repeatDays || []
      });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteSchedule = (id) => {
      if(window.confirm("Xóa lịch gốc này sẽ xóa toàn bộ các ca làm việc (Tasks) chưa hoàn thành liên quan. Tiếp tục?")) {
          deleteRelatedTasks(id);
          deleteSchedule(id);
      }
  };

  const handleDayToggle = (dayKey) => {
      setScheduleForm(prev => {
          const exists = prev.repeatDays.includes(dayKey);
          return { ...prev, repeatDays: exists ? prev.repeatDays.filter(d => d !== dayKey) : [...prev.repeatDays, dayKey] };
      });
  };

  // --- LOGIC: INLINE EDIT TASK (Mục 4) ---
  const startEditTask = (t) => {
      setEditingTaskId(t.id);
      setEditTaskData({
          title: t.title, assigneeId: t.assigneeId, assignedRole: t.assignedRole,
          startTime: t.startTime ? t.startTime.slice(0, 16) : '', 
          endTime: t.endTime ? t.endTime.slice(0, 16) : ''
      });
  };

  const saveEditTask = () => {
      if(updateTask) {
          const staff = staffList.find(s => s.id === editTaskData.assigneeId);
          updateTask(editingTaskId, {
              ...editTaskData,
              assigneeName: staff ? staff.name : 'Unknown'
          });
          alert("Lưu thay đổi thành công!");
      } else {
          alert("Hệ thống chưa hỗ trợ updateTask trực tiếp.");
      }
      setEditingTaskId(null);
  };

  // --- DATA FILTERS ---
  const taskPlusList = tasks.filter(t => !t.fromScheduleId); // Mục 3
  
  const filteredScheduleTasks = tasks.filter(t => { // Mục 4 (Các ca làm việc)
      if (!t.fromScheduleId) return false;
      const d = new Date(t.startTime);
      const matchStaff = filterTaskStaff === 'all' || t.assigneeId === filterTaskStaff;
      let matchDay = true;
      if (filterTaskDay !== 'all') matchDay = d.getDay() === daysOfWeek.find(x => x.key === filterTaskDay)?.val;
      let matchTime = true;
      if (filterTaskTime === 'day') matchTime = isSameDay(d, new Date());
      if (filterTaskTime === 'week') matchTime = isSameWeek(d, new Date());
      if (filterTaskTime === 'month') matchTime = isSameMonth(d, new Date());
      return matchStaff && matchDay && matchTime;
  });

  const searchedAdminSchedules = schedules.filter(s => { // Mục 4 (Lịch gốc)
      if (!scheduleSearchTerm.trim()) return true;
      const term = scheduleSearchTerm.toLowerCase();
      return (s.title && s.title.toLowerCase().includes(term)) || (s.assigneeName && s.assigneeName.toLowerCase().includes(term));
  });

  // --- RENDER DYNAMICAL VIEWS ---
  return (
    <div style={{ paddingBottom: '20px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #e5e7eb', paddingBottom: '15px', marginBottom: '20px', fontWeight: 'bold', fontSize: '1.5rem' }}>
          {isScheduler ? 'LÊN LỊCH CÔNG TÁC (SCHEDULER)' : 'QUẢN LÝ NHIỆM VỤ - OPERATIONS'}
      </h2>

      {activeView === 'overview' && (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px' }}>
              {isApprover && (
                  <div style={styles.menuCard}>
                      <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                          <div style={styles.iconBox}><Icons.Task /></div>
                          <h3 style={styles.cardTitle}>1. Giao nhiệm vụ (Task+)</h3>
                      </div>
                      <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Giao việc độc lập, kèm ngân sách và mức kỷ luật.</div>
                      <button onClick={() => setActiveView('create_task')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
                  </div>
              )}
              
              <div style={styles.menuCard}>
                  <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                      <div style={styles.iconBox}><Icons.Schedule /></div>
                      <h3 style={styles.cardTitle}>2. Lên lịch công tác định kỳ</h3>
                  </div>
                  <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Thiết lập ca làm việc định kỳ cho nhân sự.</div>
                  <button onClick={() => setActiveView('create_schedule')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
              </div>

              {isApprover && (
                  <div style={styles.menuCard}>
                      <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                          <div style={styles.iconBox}><Icons.Task /></div>
                          <h3 style={styles.cardTitle}>3. Quản lý nhiệm vụ (Task+)</h3>
                      </div>
                      <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Theo dõi và quản lý các nhiệm vụ độc lập đã giao.</div>
                      <button onClick={() => setActiveView('manage_tasks')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
                  </div>
              )}

              <div style={styles.menuCard}>
                  <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                      <div style={styles.iconBox}><Icons.Schedule /></div>
                      <h3 style={styles.cardTitle}>4. Quản lý công tác định kỳ</h3>
                  </div>
                  <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Quản lý lịch gốc và chỉnh sửa trực tiếp các ca làm việc.</div>
                  <button onClick={() => setActiveView('manage_schedules')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
              </div>
          </div>
      )}

      {/* TABS NỘI DUNG CHI TIẾT */}

      {/* TAB 1: CREATE TASK PLUS */}
      {activeView === 'create_task' && isApprover && (
          <div style={styles.card}>
              <div style={{display:'flex', justifyContent:'space-between', marginBottom:'20px'}}>
                  <h4 style={{margin:0, color:'#003366'}}>Giao nhiệm vụ (TASK+) & Thiết lập Kỷ luật</h4>
                  <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn</button>
              </div>
              <form onSubmit={handleAddTaskPlus} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '16px' }}>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Tiêu đề công việc</label><input value={taskPlusForm.title} onChange={e => setTaskPlusForm({...taskPlusForm, title: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Người thực hiện</label><select value={taskPlusForm.assigneeId} onChange={e => setTaskPlusForm({...taskPlusForm, assigneeId: e.target.value})} style={styles.select} required><option value="">-- Chọn nhân sự --</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}</select></div>
                  <div><label style={styles.label}>Vai trò</label><select value={taskPlusForm.assignedRole} onChange={e => setTaskPlusForm({...taskPlusForm, assignedRole: e.target.value})} style={styles.select}>{['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}</select></div>
                  <div><label style={styles.label}>Bắt đầu (Check-in)</label><input type="datetime-local" value={taskPlusForm.startTime} onChange={e => setTaskPlusForm({...taskPlusForm, startTime: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Hạn chót (Deadline)</label><input type="datetime-local" value={taskPlusForm.endTime} onChange={e => setTaskPlusForm({...taskPlusForm, endTime: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Mức tiền chi trả (VNĐ)</label><input type="number" placeholder="Ví dụ: 150000" value={taskPlusForm.paymentAmount} onChange={e => setTaskPlusForm({...taskPlusForm, paymentAmount: e.target.value})} style={styles.input} /></div>
                  <div><label style={styles.label}>Kỷ luật (nếu trễ)</label><select value={taskPlusForm.disciplineId} onChange={e => setTaskPlusForm({...taskPlusForm, disciplineId: e.target.value})} style={{...styles.select, borderColor:'red', color:'#b91c1c'}}><option value="">-- Chọn hình thức --</option>{activeDisciplines.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select></div>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Mô tả</label><textarea value={taskPlusForm.description} onChange={e => setTaskPlusForm({...taskPlusForm, description: e.target.value})} style={{...styles.input, height: '80px'}} /></div>
                  <button type="submit" style={styles.btnSubmit}>Lưu nhiệm vụ</button>
              </form>
          </div>
      )}

      {/* TAB 2: CREATE SCHEDULE */}
      {activeView === 'create_schedule' && (
          <div style={styles.card}>
              <div style={{display:'flex', justifyContent:'space-between', marginBottom:'20px'}}>
                  <h4 style={{margin:0, color:'#003366'}}>{editingScheduleId ? 'Chỉnh sửa Lịch công tác' : 'Lên lịch công tác định kỳ'}</h4>
                  <button onClick={() => {setActiveView('overview'); setEditingScheduleId(null);}} style={styles.backBtn}><Icons.Back /> Ẩn</button>
              </div>
              <form onSubmit={handleAddSchedule} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '16px' }}>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Tiêu đề lịch</label><input value={scheduleForm.title} onChange={e => setScheduleForm({...scheduleForm, title: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Người thực hiện</label><select value={scheduleForm.assigneeId} onChange={e => setScheduleForm({...scheduleForm, assigneeId: e.target.value})} style={styles.select} required><option value="">-- Chọn nhân sự --</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}</select></div>
                  <div><label style={styles.label}>Vai trò</label><select value={scheduleForm.assignedRole} onChange={e => setScheduleForm({...scheduleForm, assignedRole: e.target.value})} style={styles.select}>{['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}</select></div>
                  <div><label style={styles.label}>Thời gian bắt đầu</label><input type="datetime-local" value={scheduleForm.startTime} onChange={e => setScheduleForm({...scheduleForm, startTime: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Thời gian kết thúc</label><input type="datetime-local" value={scheduleForm.endTime} onChange={e => setScheduleForm({...scheduleForm, endTime: e.target.value})} style={styles.input} required /></div>
                  
                  <div style={{ gridColumn: '1 / -1', background: '#f9fafb', padding: '15px', borderRadius: '8px', border: '1px solid #e5e7eb' }}>
                      <h5 style={{margin:'0 0 10px 0', fontSize:'0.9rem', color:'#003366'}}>Cấu hình lặp lại</h5>
                      <div style={{display:'flex', alignItems:'center', gap:'20px', flexWrap:'wrap'}}>
                          <div><label style={styles.label}>Số tuần:</label><input type="number" min="1" max="52" value={scheduleForm.repeatWeeks} onChange={e => setScheduleForm({...scheduleForm, repeatWeeks: e.target.value})} style={{...styles.input, width: '100px'}} /></div>
                          <div>
                              <label style={styles.label}>Chọn thứ:</label>
                              <div style={{display:'flex', gap:'8px', marginTop:'5px', flexWrap: 'wrap'}}>
                                  {daysOfWeek.map(d => (
                                      <div key={d.key} onClick={() => handleDayToggle(d.key)} style={{ width:'32px', height:'32px', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.8rem', cursor:'pointer', fontWeight:'bold', border: '1px solid #d1d5db', background: scheduleForm.repeatDays.includes(d.key) ? '#003366' : 'white', color: scheduleForm.repeatDays.includes(d.key) ? 'white' : '#6b7280' }}>{d.label}</div>
                                  ))}
                              </div>
                          </div>
                      </div>
                  </div>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Mô tả</label><textarea value={scheduleForm.description} onChange={e => setScheduleForm({...scheduleForm, description: e.target.value})} style={{...styles.input, height: '80px'}} /></div>
                  <button type="submit" style={styles.btnSubmit}>{editingScheduleId ? (isScheduler ? 'Gửi yêu cầu sửa' : 'Cập nhật Lịch & Tạo Ca') : 'Lưu lịch & Tạo Ca làm việc'}</button>
              </form>
          </div>
      )}

      {/* TAB 3: MANAGE TASKS (Độc lập) */}
      {activeView === 'manage_tasks' && isApprover && (
          <div style={styles.card}>
              <div style={{display:'flex', justifyContent:'space-between', marginBottom:'20px'}}>
                  <h4 style={{margin:0, color:'#003366'}}>Danh sách Nhiệm vụ (Task+)</h4>
                  <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn</button>
              </div>
              <div style={{overflowX: 'auto'}}>
                  <table style={styles.table}>
                     <thead><tr style={styles.thRow}><th>STT</th><th>Nhiệm vụ</th><th>Người làm</th><th>Kỷ luật</th><th>Thời gian</th><th>Tiến độ</th><th>Hành động</th></tr></thead>
                     <tbody>
                        {taskPlusList.map((t, i) => (
                           <tr key={t.id} style={styles.tr}>
                               <td style={{textAlign:'center', fontWeight:'bold'}}>{i+1}</td>
                               <td><strong>{t.title}</strong><br/><span style={{fontSize:'0.75rem', color:'#059669'}}>{t.paymentType}</span></td>
                               <td>{t.assigneeName}</td>
                               <td style={{color:'red'}}>{t.disciplineName}</td>
                               <td>{formatTaskTime(t.startTime, t.endTime)}</td>
                               <td>{t.progress || 0}%</td>
                               <td><button onClick={()=>handleDeleteTask(t.id)} style={styles.actionBtnDelete}>Xóa</button></td>
                           </tr>
                        ))}
                     </tbody>
                  </table>
              </div>
          </div>
      )}

      {/* TAB 4: MANAGE SCHEDULES & INLINE EDIT TASKS */}
      {activeView === 'manage_schedules' && (
          <div>
              {/* 4.1 Bảng Lịch Gốc */}
              <div style={{...styles.card, marginBottom: '20px'}}>
                  <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'10px', marginBottom:'20px'}}>
                      <h4 style={{margin:0, color:'#003366'}}>A. Danh sách Lịch gốc (Schedules)</h4>
                      <div style={{display:'flex', gap:'10px'}}>
                          <input type="text" placeholder="Tìm theo tiêu đề, nhân sự..." value={scheduleSearchTerm} onChange={(e) => setScheduleSearchTerm(e.target.value)} style={{...styles.input, width:'250px', marginTop:0}} />
                          <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn</button>
                      </div>
                  </div>
                  <div style={{overflowX: 'auto'}}>
                      <table style={styles.table}>
                         <thead><tr style={styles.thRow}><th>STT</th><th>Tiêu đề Lịch</th><th>Lặp lại</th><th>Hành động</th></tr></thead>
                         <tbody>
                            {searchedAdminSchedules.map((s, i) => (
                               <tr key={s.id} style={styles.tr}>
                                   <td style={{textAlign:'center', fontWeight:'bold'}}>{i+1}</td>
                                   <td><strong>{s.title}</strong><div style={{fontSize:'0.8rem', color:'#6b7280'}}>Phụ trách: {s.assigneeName} ({s.assignedRole})</div></td>
                                   <td>{s.repeatWeeks} tuần <br/><span style={{fontSize:'0.75rem', color:'#666'}}>{(s.repeatDays||[]).join(', ')}</span></td>
                                   <td>
                                       <button onClick={()=>handleEditSchedule(s)} style={styles.actionBtnEdit}>Sửa</button>
                                       <button onClick={()=>handleDeleteSchedule(s.id)} style={styles.actionBtnDelete}>Xóa</button>
                                   </td>
                               </tr>
                            ))}
                         </tbody>
                      </table>
                  </div>
              </div>

              {/* 4.2 Bảng Ca làm việc (Cho phép Inline Edit) */}
              <div style={styles.card}>
                  <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'10px', marginBottom:'20px'}}>
                      <h4 style={{margin:0, color:'#003366'}}>B. Các ca làm việc (Phát sinh từ Lịch)</h4>
                      <div style={{display:'flex', gap:'10px'}}>
                          <select value={filterTaskStaff} onChange={e => setFilterTaskStaff(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả NS</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>
                          <select value={filterTaskTime} onChange={e => setFilterTaskTime(e.target.value)} style={styles.filterSelect}><option value="all">Thời gian</option><option value="day">Hôm nay</option><option value="week">Tuần này</option><option value="month">Tháng này</option></select>
                      </div>
                  </div>
                  <div style={{overflowX: 'auto'}}>
                      <table style={styles.table}>
                         <thead><tr style={styles.thRow}><th>STT</th><th>Nhiệm vụ</th><th>Người làm</th><th>Vai trò</th><th>Check-in</th><th>Check-out</th><th>Sửa</th></tr></thead>
                         <tbody>
                            {filteredScheduleTasks.map((t, i) => {
                                const isEditing = editingTaskId === t.id;
                                return (
                                   <tr key={t.id} style={{...styles.tr, background: isEditing ? '#f0f9ff' : 'transparent'}}>
                                       <td style={{textAlign:'center', fontWeight:'bold'}}>{i+1}</td>
                                       <td>{isEditing ? <input value={editTaskData.title} onChange={e=>setEditTaskData({...editTaskData, title: e.target.value})} style={styles.inlineInput}/> : <strong>{t.title}</strong>}</td>
                                       <td>{isEditing ? <select value={editTaskData.assigneeId} onChange={e=>setEditTaskData({...editTaskData, assigneeId: e.target.value})} style={styles.inlineInput}>{staffList.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}</select> : t.assigneeName}</td>
                                       <td>{isEditing ? <select value={editTaskData.assignedRole} onChange={e=>setEditTaskData({...editTaskData, assignedRole: e.target.value})} style={styles.inlineInput}>{['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r=><option key={r} value={r}>{r}</option>)}</select> : t.assignedRole}</td>
                                       <td>{isEditing ? <input type="datetime-local" value={editTaskData.startTime} onChange={e=>setEditTaskData({...editTaskData, startTime: e.target.value})} style={styles.inlineInput}/> : new Date(t.startTime).toLocaleString('vi-VN')}</td>
                                       <td>{isEditing ? <input type="datetime-local" value={editTaskData.endTime} onChange={e=>setEditTaskData({...editTaskData, endTime: e.target.value})} style={styles.inlineInput}/> : new Date(t.endTime).toLocaleString('vi-VN')}</td>
                                       <td>
                                           {isEditing ? (
                                               <div style={{display:'flex', gap:'5px'}}>
                                                   <button onClick={saveEditTask} style={styles.actionBtnSave}>Lưu</button>
                                                   <button onClick={()=>setEditingTaskId(null)} style={styles.actionBtnCancel}>Hủy</button>
                                               </div>
                                           ) : (
                                               <button onClick={()=>startEditTask(t)} style={styles.actionBtnEdit}><Icons.Edit /></button>
                                           )}
                                       </td>
                                   </tr>
                                )
                            })}
                         </tbody>
                      </table>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

const styles = {
    card: { background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', border: '1px solid #e5e7eb' },
    input: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', boxSizing: 'border-box' },
    inlineInput: { width: '100%', padding: '6px', borderRadius: '4px', border: '1px solid #003366', boxSizing: 'border-box', fontSize: '0.8rem' },
    select: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', background: 'white' },
    filterSelect: { padding: '6px 12px', borderRadius: '6px', border: '1px solid #d1d5db', outline: 'none', color: '#374151', cursor: 'pointer', background:'white' },
    label: { fontSize: '0.8rem', fontWeight: 'bold', color: '#555' },
    btnSubmit: { gridColumn: '1 / -1', padding: '12px', background: '#003366', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' },
    menuCard: { background: 'white', borderRadius: '12px', padding: '20px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e5e7eb', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', minHeight: '150px' },
    iconBox: { width: '36px', height: '36px', background: '#e0f2fe', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#003366' },
    cardTitle: { margin: 0, fontSize: '1rem', fontWeight: '600', color: '#1f2937' },
    accessBtn: { marginTop: 'auto', background: '#003366', color: 'white', border: 'none', padding: '10px 16px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', transition: 'background 0.2s' },
    backBtn: { background: '#fef2f2', color: '#ef4444', border: '1px solid #fecaca', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '6px' },
    table: { width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem', minWidth: '800px' },
    thRow: { textAlign:'left', borderBottom: '1px solid #eee', background:'#f9fafb', color:'#6b7280' },
    tr: { borderBottom: '1px solid #f9f9f9' },
    actionBtnEdit: { color:'#003366', border:'1px solid #003366', background:'white', padding:'4px 8px', borderRadius:'6px', cursor:'pointer', marginRight:'5px', fontWeight:'600' },
    actionBtnDelete: { color:'#dc2626', border:'1px solid #fecaca', background:'#fef2f2', padding:'4px 8px', borderRadius:'6px', cursor:'pointer', fontWeight:'600' },
    actionBtnSave: { background: '#16a34a', color: 'white', border: 'none', padding: '6px 10px', borderRadius: '4px', cursor: 'pointer', fontWeight: 'bold' },
    actionBtnCancel: { background: '#9ca3af', color: 'white', border: 'none', padding: '6px 10px', borderRadius: '4px', cursor: 'pointer', fontWeight: 'bold' }
};

export default TaskManager;
